class CosmosQuery
{
    void FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        // Also uses sync APIs
        var products = ctx.Products.Where(p => p.Sku == "ABC").ToList();
    }
}

arguments.new_str:
using Microsoft.EntityFrameworkCore;
class CosmosQuery
{
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — safe: we configured HasDiscriminator("Discriminator")
        // so existing documents still use c.Discriminator, not c.$type.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 Cosmos no longer supports sync I/O; use async.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

